const slackData = $('Extract Slash Command Data').first().json;
const lookupResult = $('Lookup User').first().json;

// Resolve assistant identity (user override -> defaults)
let assistantName = 'Backstory';
let assistantEmoji = ':robot_face:';
let assistantPersona = 'direct, action-oriented, conversational';
let dbUserId = null;

if (lookupResult && lookupResult.id) {
  if (lookupResult.assistant_name) assistantName = lookupResult.assistant_name;
  if (lookupResult.assistant_emoji) assistantEmoji = lookupResult.assistant_emoji;
  if (lookupResult.assistant_persona) assistantPersona = lookupResult.assistant_persona;
  dbUserId = lookupResult.id;
}


// BBR/PBR detection — extract account name
const commandText = slackData.commandText || '';
const commandLower = commandText.toLowerCase();
const bbrPatterns = [/\bbbr\b/, /\bpbr\b/, /business review/i, /backstory business review/i, /people\.?ai business review/i];
const isBBR = bbrPatterns.some(p => p.test(commandLower));
let bbrAccount = null;
if (isBBR) {
  bbrAccount = commandText
    .replace(/\b(bbr|pbr|business\s+review|backstory\s+business\s+review|people\.?ai\s+business\s+review|for|with|about|on|create|make|generate|build|a|the|presentation|deck|slide|slides)\b/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// Presentation detection
const presPatterns = [/^presentation\b/i, /^pres\b/i, /^slides?\b/i, /^deck\b/i];
const isPresentation = presPatterns.some(p => p.test(commandLower));
let presentationPrompt = null;
if (isPresentation) {
  presentationPrompt = commandText
    .replace(/^(presentation|pres|slides?|deck)\s*/i, '')
    .trim();
}

// Build system prompt
const systemPrompt = [
  'You are ' + assistantName + ', a personal sales assistant for ' + slackData.userName + '. You work exclusively for them.',
  '',
  'Your personality: ' + assistantPersona,
  '',
  'You have access to People.ai MCP tools which give you CRM data, account activity, opportunity details, engagement scores, and communication summaries.',
  '',
  '**INSTRUCTIONS:**',
  '- Use the People.ai MCP tools to answer the user\'s question with real data.',
  '- Be concise and actionable — this response will be posted in Slack.',
  '- Format your response using Slack markdown: *bold*, _italic_, `code`.',
  '- Use bullet points sparingly and keep them short.',
  '- If the question is about a specific account or opportunity, include key metrics (engagement level, amount, stage, etc.).',
  '- If you can\'t find the requested data, say so clearly rather than guessing.',
  '- Keep your total response under 3000 characters so it displays well in Slack.',
  '- Do NOT use headers with ### or ** section headers ** — just use *bold* for emphasis.',
  '- End with a brief actionable recommendation when relevant.',

  '',
  '## PRESENTATIONS',
  'If the user asks you to create a presentation, slides, or deck, respond:',
  '"I\'ll create that presentation for you now! Building your Backstory deck..."',
  'Do NOT generate pptxgenjs code or any code. The presentation system handles this automatically.',
].join('\n');

// Pre-format Slack messages
const headerText = assistantEmoji + ' ' + assistantName + '  —  @' + slackData.userName + '\'s personal assistant:';
const thinkingText = headerText + '\n\n⏳ Thinking...';
const answeredText = headerText + '\n\n✅ Answered in thread';

return [{
  json: {
    ...slackData,
    assistantName,
    assistantEmoji,
    assistantPersona,
    dbUserId,
    systemPrompt,
    isBBR,
    bbrAccount,
    isPresentation,
    presentationPrompt,
    headerText,
    thinkingText,
    answeredText
  }
}];

/**
 * Extract Slash Command Data
 */
const webhookData = $('Slash Command Webhook').first().json;

function findField(fieldName) {
  if (webhookData[fieldName] !== undefined && webhookData[fieldName] !== '') {
    return String(webhookData[fieldName]);
  }
  if (webhookData.body && typeof webhookData.body === 'object' && webhookData.body[fieldName] !== undefined) {
    return String(webhookData.body[fieldName]);
  }
  if (webhookData.body && typeof webhookData.body === 'string') {
    const params = new URLSearchParams(webhookData.body);
    const val = params.get(fieldName);
    if (val) return val;
  }
  if (webhookData.query && webhookData.query[fieldName]) {
    return String(webhookData.query[fieldName]);
  }
  return '';
}

const userId = findField('user_id');
const userName = findField('user_name');
const channelId = findField('channel_id');
const responseUrl = findField('response_url');
const commandText = findField('text');

return [{
  json: {
    userId,
    userName,
    channelId,
    responseUrl,
    commandText
  }
}];

